{
    None = 0,
    Enabled = 1 << 0,
    Focused = 1 << 1,
    Checked = 1 << 2,
    Selected = 1 << 3,
    Expanded = 1 << 4,
    Collapsed = 1 << 5,
    Busy = 1 << 6,
    ReadOnly = 1 << 7,
    Required = 1 << 8,
    Invalid = 1 << 9,
    Invisible = 1 << 10,
    Multiline = 1 << 11,
